class Solution {
    public int rearrangeCharacters(String s, String target) {
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j < s.length(); j++) {
                if (s.charAt(i) == target.charAt(0)) {
                    int j_target = 0;
                    while (j_target < target.length() && s.charAt(j) == target.charAt(j_target)) {
                        j_target++;
                    }
                    count += j - i;
                }
            }
        }
        return count;
    }
}
